SELECT *
FROM demographic_breakdown
WHERE gender IN ('Male', 'Female');

SELECT ethnicity_id, ethnicity_name 
FROM ethnicities 
WHERE ethnicity_id > 2 AND ethnicity_name LIKE 'S%';

SELECT DISTINCT geographic_location 
FROM demographic_data 
WHERE year_id = (SELECT MAX(year_id) FROM demographic_data);

SELECT COUNT(DISTINCT user_id)
FROM user_access
WHERE access_type = 'edit';

SELECT population, percentage, age_group, gender
FROM demographic_breakdown
WHERE ethnicity_id = 1;
